186	    __forceinline__ __device__ __host__
187	    TokenLayout(const int& num_hidden_bytes, const int& num_sf_bytes,
188	                const int& num_topk, const bool& with_metadata, void* base = nullptr) :
189	        num_hidden_bytes(num_hidden_bytes),
190	        num_sf_bytes(num_sf_bytes),
191	        // Metadata includes: top-k indices, weight and source rank/token index
192	        with_metadata(with_metadata),
193	        num_topk(num_topk),
194	        num_metadata_bytes(num_topk * (sizeof(int) + sizeof(float)) +
195	                           (with_metadata ? (1 + num_topk) * sizeof(int) : 0)),
196	        base(base) {
197	        EP_STATIC_ASSERT(sizeof(int) == sizeof(float), "Invalid size assumption");
198	        EP_UNIFIED_ASSERT(num_hidden_bytes % ptx::kNumTMAAlignBytes == 0);
