202	    __forceinline__ __device__ __host__ dtype_t get_num_bytes() const {
203	        const auto num_bytes = math::align(num_hidden_bytes, ptx::kNumTMAAlignBytes) +
204	                               math::align(num_sf_bytes, ptx::kNumTMAAlignBytes) +
205	                               math::align(num_metadata_bytes, ptx::kNumTMAAlignBytes) +
206	                               math::align<int>(kWithMBarrier ? sizeof(ptx::mbarrier) : 0, ptx::kNumTMAAlignBytes);
207	        return static_cast<dtype_t>(num_bytes);
208	    }
