215	        base = ptr;
216	    }
217	
218	    __forceinline__ __device__ __host__ void* get_hidden_ptr() const {
219	        return get_base_ptr();
220	    }
221	
222	    __forceinline__ __device__ __host__ sf_pack_t* get_sf_ptr() const {
223	        return math::advance_ptr<sf_pack_t>(base, math::align(num_hidden_bytes, ptx::kNumTMAAlignBytes));
224	    }
225	
226	    __forceinline__ __device__ __host__ int* get_metadata_ptr() const {
227	        return math::advance_ptr<int>(get_sf_ptr(), math::align(num_sf_bytes, ptx::kNumTMAAlignBytes));
228	    }
229	
