262	        // Buffer layouts
263	        const auto token_layout = layout::TokenLayout(kNumHiddenBytes, kNumSFPacks * sizeof(sf_pack_t), kNumTopk, true);
264	        const auto tma_buffer = layout::BufferLayout<true>(token_layout, kNumDispatchWarps, 1,
265	            math::advance_ptr<int>(smem, kNumSmemBytesForNotify)).get_rank_buffer(dispatch_warp_idx).get_token_buffer(0);
266	        auto recv_buffer = layout::BufferLayout<false>(token_layout, kNumRanks, kNumMaxTokensPerRank, buffer);
267	        auto send_buffer = layout::BufferLayout<false>(token_layout, 1, kNumMaxTokensPerRank, recv_buffer.get_buffer_end_ptr());
268	        recv_buffer = recv_buffer.get_rank_buffer(rank_idx);
269	
270	        // Init TMA
271	        ptx::arrival_phase phase = 0;
272	        const auto mbarrier_ptr = tma_buffer.get_mbarrier_ptr();
273	        if (ptx::elect_one_sync())
274	            ptx::mbarrier_init_with_fence(mbarrier_ptr, 1);
275	        __syncwarp();
276	
277	        // Iterate all tokens
278	        const auto token_start = dispatch_warp_idx * kNumSMs + sm_idx;
279	        const auto token_stride = kNumDispatchWarps * kNumSMs;
280	        for (int token_idx = token_start; token_idx < num_tokens; token_idx += token_stride) {
281	            const auto token_i64_idx = static_cast<int64_t>(token_idx);
282	
283	            // Wait TMA store arrivals
284	            ptx::tma_store_wait();
285	            __syncwarp();
286	
287	            // Issue data TMA
288	            if (ptx::elect_one_sync()) {
289	                ptx::tma_load_1d(tma_buffer.get_hidden_ptr(), math::advance_ptr(x, token_i64_idx * kNumHiddenBytes),
290	                                 mbarrier_ptr, kNumHiddenBytes);
291	            }
292	            __syncwarp();
293	
294	            // Issue SF TMA or cp.async
295	            if constexpr (kNumSFPacks > 0) {
296	                EP_STATIC_ASSERT(sizeof(sf_pack_t) % 4 == 0, "Unaligned SF element type");
297	                const auto gmem_src_ptr = math::advance_ptr<sf_pack_t>(sf, token_i64_idx * sf_token_stride * sizeof(sf_pack_t));
298	                const auto smem_dst_ptr = tma_buffer.get_sf_ptr();
299	
300	                constexpr auto kNumFullIters = kNumSFPacks / 32;
301	                #pragma unroll
302	                for (int k = 0; k < kNumFullIters; ++ k) {
303	                    ptx::cp_async_ca(gmem_src_ptr + (k * 32 + lane_idx) * sf_hidden_stride,
304	                                     smem_dst_ptr + k * 32 + lane_idx);
305	                }
306	                if (kNumFullIters * 32 + lane_idx < kNumSFPacks) {
307	                    ptx::cp_async_ca(gmem_src_ptr + (kNumFullIters * 32 + lane_idx) * sf_hidden_stride,
308	                                     smem_dst_ptr + kNumFullIters * 32 + lane_idx);
309	                }
310	                ptx::cp_async_mbarrier_arrive(mbarrier_ptr);
311	                __syncwarp();
312	            }
313	
314	            // Load top-k indices and weights
315	            EP_STATIC_ASSERT(kNumTopk <= 32, "Insufficient lanes for loading top-k indices");
316	            int stored_dst_rank_idx = -1;
317	            if (lane_idx < kNumTopk) {
318	                const auto uncasted_dst_expert_idx = __ldg(topk_idx + token_idx * kNumTopk + lane_idx);
319	                const auto dst_expert_idx = static_cast<int>(uncasted_dst_expert_idx);
320	                stored_dst_rank_idx = dst_expert_idx >= 0 ? dst_expert_idx / kNumExpertsPerRank : -1;
321	                tma_buffer.get_topk_idx_ptr()[lane_idx] = dst_expert_idx;
322	                if (topk_weights != nullptr)
323	                    tma_buffer.get_topk_weights_ptr()[lane_idx] = __ldg(topk_weights + token_idx * kNumTopk + lane_idx);
324	                if (copied_topk_idx != nullptr)
325	                    copied_topk_idx[token_idx * kNumTopk + lane_idx] = uncasted_dst_expert_idx;
326	            }
327	            __syncwarp();
328	
329	            // Add source metadata (rank index and token index)
330	            // Please ensure no TMA buffer shared memory writes after this part
331	            if (ptx::elect_one_sync())
332	                *tma_buffer.get_src_token_global_idx_ptr() = rank_idx * kNumMaxTokensPerRank + token_idx;
333	            ptx::tma_store_fence();
334	            __syncwarp();
335	
336	            // Deduplicate ranks and assign slots
337	            int stored_dst_slot_idx = -1;
338	            if constexpr (kReuseSlotIndices) {
339	                if (lane_idx < kNumTopk)
340	                    stored_dst_slot_idx = __ldg(dst_buffer_slot_idx + token_idx * kNumTopk + lane_idx);
341	                stored_dst_slot_idx = stored_dst_slot_idx >= 0 ?
342	                    (stored_dst_slot_idx - rank_idx * kNumMaxTokensPerRank) : -1;
343	            } else {
344	                if (ptx::deduplicate(stored_dst_rank_idx, lane_idx) and stored_dst_rank_idx >= 0)
345	                    stored_dst_slot_idx = atomicAdd(workspace_layout.get_scaleup_atomic_sender_counter() + stored_dst_rank_idx, 1);
346	                if (lane_idx < kNumTopk) {
347	                    const auto value = stored_dst_slot_idx >= 0 ?
348	                        rank_idx * kNumMaxTokensPerRank + stored_dst_slot_idx : -1;
349	                    dst_buffer_slot_idx[token_idx * kNumTopk + lane_idx] = value;
350	                }
351	            }
352	            __syncwarp();
353	
354	            // Wait TMA load arrival
355	            // NOTES: this arrive must be after the `ptx::cp_async_mbarrier_arrive`
356	            if (ptx::elect_one_sync()) {
357	                ptx::mbarrier_arrive_and_set_tx(mbarrier_ptr, kNumHiddenBytes);
358	                ptx::mbarrier_wait_and_flip_phase(mbarrier_ptr, phase);
359	            }
360	            __syncwarp();
361	
362	            // TMA store to send buffer
363	            auto send_buffer_ptr = send_buffer.get_token_buffer(token_idx).get_base_ptr();
364	            if constexpr (not kIsScaleupNVLink) {
365	                if (ptx::elect_one_sync())
366	                    ptx::tma_store_1d(send_buffer_ptr, tma_buffer.get_base_ptr(), tma_buffer.get_num_bytes<false>());
367	                ptx::tma_store_commit();
368	                __syncwarp();
369	            }
370	
371	            // Issue TMA NVLink stores
372	            EP_STATIC_ASSERT(kNumTopk <= 32, "Invalid top-k selection");
373	            const auto dst_ptr = stored_dst_slot_idx >= 0 ?
374	                gin.get_sym_ptr<team_t>(recv_buffer.get_token_buffer(stored_dst_slot_idx).get_base_ptr(), stored_dst_rank_idx) :
375	                nullptr;
376	            if (dst_ptr != nullptr)
377	                ptx::tma_store_1d(dst_ptr, tma_buffer.get_base_ptr(), tma_buffer.get_num_bytes<false>());
378	            ptx::tma_store_commit();
379	            __syncwarp();
380	
381	            // Issue RDMA put
382	            if constexpr (not kIsScaleupNVLink) {
383	                // Wait the send buffer store to arrive
384	                ptx::tma_store_wait<1>();
385	                __syncwarp();
